    public readonly record struct OverloadExpectation(string? Value, Type? ExceptionType, bool ExpectsAnyException = false)
    {
        public bool ExpectsException => ExpectsAnyException || ExceptionType is not null;
    }

    static OverloadExpectation Value(string value) => new(value, null);

    static OverloadExpectation AnyException() => new(null, null, true);

    static OverloadExpectation Exception<TException>() where TException : Exception => new(null, typeof(TException));
}

